import { Button, Card, List, Select, Space, Tooltip, Typography, message } from "antd";
import { PlusOutlined } from "@ant-design/icons";
import { useEffect, useMemo, useState } from "react";
import { addItemToCart, getMenus, getRestaurants } from "../utils";

const { Paragraph, Text, Title } = Typography;

const AddToCartButton = ({ itemId, onAdded }) => {
  const [loading, setLoading] = useState(false);

  const addToCart = () => {
    setLoading(true);
    addItemToCart(itemId)
      .then(() => {
        message.success("Added item to cart");
        onAdded();
      })
      .catch((err) => {
        message.error(err.message);
      })
      .finally(() => {
        setLoading(false);
      });
  };

  return (
    <Tooltip title="Add to cart">
      <Button
        loading={loading}
        type="primary"
        icon={<PlusOutlined />}
        onClick={addToCart}
      />
    </Tooltip>
  );
};

const FoodList = ({ onItemAdded }) => {
  const [foodData, setFoodData] = useState([]);
  const [currentRestaurantId, setCurrentRestaurantId] = useState();
  const [restaurants, setRestaurants] = useState([]);
  const [loadingMenus, setLoadingMenus] = useState(false);
  const [loadingRestaurants, setLoadingRestaurants] = useState(false);

  useEffect(() => {
    setLoadingRestaurants(true);
    getRestaurants()
      .then((data) => {
        setRestaurants(data);
        if (data.length > 0) {
          setCurrentRestaurantId(data[0].id);
        }
      })
      .catch((err) => {
        message.error(err.message);
      })
      .finally(() => {
        setLoadingRestaurants(false);
      });
  }, []);

  useEffect(() => {
    if (!currentRestaurantId) {
      return;
    }

    setLoadingMenus(true);
    getMenus(currentRestaurantId)
      .then((data) => {
        setFoodData(data);
      })
      .catch((err) => {
        message.error(err.message);
      })
      .finally(() => {
        setLoadingMenus(false);
      });
  }, [currentRestaurantId]);

  const currentRestaurant = useMemo(
    () => restaurants.find((item) => item.id === currentRestaurantId),
    [currentRestaurantId, restaurants]
  );

  return (
    <Space direction="vertical" size="large" style={{ width: "100%" }}>
      <Space direction="vertical" size="small" style={{ width: "100%" }}>
        <Title level={3} style={{ marginBottom: 0 }}>
          Restaurants
        </Title>
        <Select
          value={currentRestaurantId}
          onChange={setCurrentRestaurantId}
          placeholder="Select a restaurant"
          loading={loadingRestaurants}
          style={{ maxWidth: 360 }}
          options={restaurants.map((item) => ({
            label: item.name,
            value: item.id,
          }))}
        />
      </Space>

      {currentRestaurant && (
        <Card>
          <Space direction="vertical" size="small">
            <Title level={4} style={{ marginBottom: 0 }}>
              {currentRestaurant.name}
            </Title>
            <Text type="secondary">{currentRestaurant.address}</Text>
            <Text type="secondary">{currentRestaurant.phone}</Text>
          </Space>
        </Card>
      )}

      <List
        loading={loadingMenus}
        grid={{
          gutter: 16,
          xs: 1,
          sm: 2,
          md: 2,
          lg: 3,
          xl: 3,
          xxl: 4,
        }}
        dataSource={foodData}
        renderItem={(item) => (
          <List.Item key={item.id}>
            <Card
              title={item.name}
              extra={<AddToCartButton itemId={item.id} onAdded={onItemAdded} />}
              cover={
                <img
                  src={item.image_url}
                  alt={item.name}
                  style={{ aspectRatio: "16 / 9", objectFit: "cover" }}
                />
              }
            >
              <Space direction="vertical" size="small">
                <Paragraph ellipsis={{ rows: 3, expandable: false }} style={{ marginBottom: 0 }}>
                  {item.description || "No description available."}
                </Paragraph>
                <Text strong>{`$${item.price?.toFixed(2)}`}</Text>
              </Space>
            </Card>
          </List.Item>
        )}
      />
    </Space>
  );
};

export default FoodList;
