import { Button, Card, Form, Input, Typography, message } from "antd";
import React from "react";
import { LockOutlined, UserOutlined } from "@ant-design/icons";
import { login } from "../utils";

const { Paragraph, Text, Title } = Typography;

class LoginForm extends React.Component {
  state = {
    loading: false,
  };

  onFinish = (data) => {
    this.setState({
      loading: true,
    });

    login(data)
      .then(() => {
        message.success("Login successful");
        this.props.onSuccess();
      })
      .catch((err) => {
        message.error(err.message);
      })
      .finally(() => {
        this.setState({
          loading: false,
        });
      });
  };

  render = () => {
    return (
      <Card style={{ margin: "48px auto 0", maxWidth: 420 }}>
        <Title level={3}>Sign In</Title>
        <Paragraph type="secondary">
          Demo account: <Text code>demo@laifood.com</Text> / <Text code>demo123</Text>
        </Paragraph>

        <Form name="login" onFinish={this.onFinish} layout="vertical">
          <Form.Item
            label="Email"
            name="username"
            rules={[{ required: true, message: "Please input your email" }]}
          >
            <Input prefix={<UserOutlined />} placeholder="demo@laifood.com" />
          </Form.Item>

          <Form.Item
            label="Password"
            name="password"
            rules={[{ required: true, message: "Please input your password" }]}
          >
            <Input.Password prefix={<LockOutlined />} placeholder="demo123" />
          </Form.Item>

          <Form.Item style={{ marginBottom: 0 }}>
            <Button type="primary" htmlType="submit" loading={this.state.loading}>
              Login
            </Button>
          </Form.Item>
        </Form>
      </Card>
    );
  };
}

export default LoginForm;
