import { Button, Drawer, Empty, List, Space, Typography, message } from "antd";
import { DeleteOutlined, MinusOutlined, PlusOutlined } from "@ant-design/icons";
import { useEffect, useState } from "react";
import {
  addItemToCart,
  checkout,
  getCart,
  removeCartItem,
  updateCartItem,
} from "../utils";

const { Text } = Typography;

const MyCart = ({ cartVersion, onCartChanged }) => {
  const [cartVisible, setCartVisible] = useState(false);
  const [cartData, setCartData] = useState();
  const [loading, setLoading] = useState(false);
  const [checkingOut, setCheckingOut] = useState(false);
  const [updatingItemId, setUpdatingItemId] = useState(null);

  const refreshCart = () => {
    setLoading(true);
    getCart()
      .then((data) => {
        setCartData(data);
      })
      .catch((err) => {
        message.error(err.message);
      })
      .finally(() => {
        setLoading(false);
      });
  };

  useEffect(() => {
    if (!cartVisible) {
      return;
    }

    refreshCart();
  }, [cartVisible, cartVersion]);

  const updateItem = (orderItemId, request) => {
    setUpdatingItemId(orderItemId);
    request()
      .then(() => {
        refreshCart();
        onCartChanged();
      })
      .catch((err) => {
        message.error(err.message);
      })
      .finally(() => {
        setUpdatingItemId(null);
      });
  };

  const onIncreaseQuantity = (item) => {
    updateItem(item.order_item_id, () => addItemToCart(item.menu_item_id));
  };

  const onDecreaseQuantity = (item) => {
    updateItem(item.order_item_id, () =>
      updateCartItem(item.order_item_id, item.quantity - 1)
    );
  };

  const onRemoveItem = (item) => {
    updateItem(item.order_item_id, () => removeCartItem(item.order_item_id));
  };

  const onCheckout = () => {
    setCheckingOut(true);
    checkout()
      .then((order) => {
        message.success(`Order #${order.id} placed successfully`);
        setCartVisible(false);
        setCartData({ ...cartData, order_items: [], total_price: 0 });
        onCartChanged();
      })
      .catch((err) => {
        message.error(err.message);
      })
      .finally(() => {
        setCheckingOut(false);
      });
  };

  return (
    <>
      <Button type="primary" shape="round" onClick={() => setCartVisible(true)}>
        Cart
      </Button>
      <Drawer
        title="My Shopping Cart"
        onClose={() => setCartVisible(false)}
        open={cartVisible}
        width={560}
        footer={
          <div style={{ display: "flex", justifyContent: "space-between", gap: 16 }}>
            <Text strong>{`Total: $${(cartData?.total_price || 0).toFixed(2)}`}</Text>
            <Space>
              <Button onClick={() => setCartVisible(false)}>Close</Button>
              <Button
                onClick={onCheckout}
                type="primary"
                loading={checkingOut}
                disabled={loading || !cartData?.order_items?.length}
              >
                Checkout
              </Button>
            </Space>
          </div>
        }
      >
        {cartData?.order_items?.length ? (
          <List
            loading={loading}
            itemLayout="horizontal"
            dataSource={cartData.order_items}
            renderItem={(item) => (
              <List.Item key={item.order_item_id}>
                <List.Item.Meta
                  avatar={
                    <img
                      src={item.menu_item_image_url}
                      alt={item.menu_item_name}
                      style={{ width: 72, height: 72, objectFit: "cover" }}
                    />
                  }
                  title={item.menu_item_name}
                  description={
                    <Space direction="vertical" size={2}>
                      <Text>{`$${item.price?.toFixed(2)} each`}</Text>
                      <Text type="secondary">{`Quantity: ${item.quantity}`}</Text>
                      <Text type="secondary">{`Subtotal: $${(item.price * item.quantity).toFixed(2)}`}</Text>
                    </Space>
                  }
                />

                <Space>
                  <Button
                    icon={<MinusOutlined />}
                    disabled={updatingItemId === item.order_item_id}
                    onClick={() => onDecreaseQuantity(item)}
                  />
                  <Button
                    icon={<PlusOutlined />}
                    disabled={updatingItemId === item.order_item_id}
                    onClick={() => onIncreaseQuantity(item)}
                  />
                  <Button
                    danger
                    icon={<DeleteOutlined />}
                    disabled={updatingItemId === item.order_item_id}
                    onClick={() => onRemoveItem(item)}
                  />
                </Space>
              </List.Item>
            )}
          />
        ) : (
          <Empty
            image={Empty.PRESENTED_IMAGE_SIMPLE}
            description={loading ? "Loading cart..." : "Your cart is empty"}
          />
        )}
      </Drawer>
    </>
  );
};

export default MyCart;
