import { Button, Drawer, Empty, List, Space, Spin, Tag, Typography, message } from "antd";
import { useEffect, useState } from "react";
import { getOrders } from "../utils";

const { Text } = Typography;

const OrderHistory = () => {
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [orders, setOrders] = useState([]);

  useEffect(() => {
    if (!drawerOpen) {
      return;
    }

    setLoading(true);
    getOrders()
      .then((data) => {
        setOrders(data);
      })
      .catch((err) => {
        message.error(err.message);
      })
      .finally(() => {
        setLoading(false);
      });
  }, [drawerOpen]);

  return (
    <>
      <Button onClick={() => setDrawerOpen(true)}>Orders</Button>
      <Drawer
        title="Order History"
        width={640}
        onClose={() => setDrawerOpen(false)}
        open={drawerOpen}
      >
        {loading ? (
          <div style={{ display: "flex", justifyContent: "center", paddingTop: 60 }}>
            <Spin />
          </div>
        ) : orders.length === 0 ? (
          <Empty description="No orders yet" />
        ) : (
          <List
            dataSource={orders}
            renderItem={(order) => (
              <List.Item key={order.id}>
                <Space direction="vertical" style={{ width: "100%" }} size="small">
                  <Space wrap>
                    <Text strong>{`Order #${order.id}`}</Text>
                    <Tag color="blue">{order.status}</Tag>
                    <Text type="secondary">
                      {new Date(order.created_at).toLocaleString()}
                    </Text>
                    <Text>{`Total: $${order.total_price?.toFixed(2)}`}</Text>
                  </Space>

                  <List
                    size="small"
                    bordered
                    dataSource={order.items}
                    renderItem={(item) => (
                      <List.Item key={item.id}>
                        <Space
                          style={{ display: "flex", justifyContent: "space-between", width: "100%" }}
                        >
                          <Text>{`${item.quantity} x ${item.menu_item_name}`}</Text>
                          <Text>{`$${(item.price * item.quantity).toFixed(2)}`}</Text>
                        </Space>
                      </List.Item>
                    )}
                  />
                </Space>
              </List.Item>
            )}
          />
        )}
      </Drawer>
    </>
  );
};

export default OrderHistory;
