import { Button, Layout, Space, Spin, Typography, message } from "antd";
import { useEffect, useState } from "react";
import FoodList from "./components/FoodList";
import LoginForm from "./components/LoginForm";
import MyCart from "./components/MyCart";
import OrderHistory from "./components/OrderHistory";
import SignupForm from "./components/SignupForm";
import { getCurrentUser, logout } from "./utils";

const { Header, Content } = Layout;
const { Text, Title } = Typography;

function App() {
  const [currentUser, setCurrentUser] = useState(null);
  const [loadingSession, setLoadingSession] = useState(true);
  const [cartVersion, setCartVersion] = useState(0);

  const refreshSession = () => {
    setLoadingSession(true);
    getCurrentUser()
      .then((user) => {
        setCurrentUser(user);
      })
      .catch(() => {
        setCurrentUser(null);
      })
      .finally(() => {
        setLoadingSession(false);
      });
  };

  useEffect(() => {
    refreshSession();
  }, []);

  const handleItemAdded = () => {
    setCartVersion((value) => value + 1);
  };

  const handleCartChanged = () => {
    setCartVersion((value) => value + 1);
  };

  const handleLogout = () => {
    logout()
      .then(() => {
        setCurrentUser(null);
        setCartVersion((value) => value + 1);
        message.success("Logged out");
      })
      .catch((err) => {
        message.error(err.message);
      });
  };

  return (
    <Layout style={{ minHeight: "100vh" }}>
      <Header style={{ display: "flex", alignItems: "center", paddingInline: 24 }}>
        <div
          style={{
            alignItems: "center",
            display: "flex",
            justifyContent: "space-between",
            width: "100%",
            gap: 16,
          }}
        >
          <div>
            <Title
              level={2}
              style={{ color: "white", lineHeight: "inherit", marginBottom: 0 }}
            >
              Lai Food
            </Title>
            <Text style={{ color: "rgba(255, 255, 255, 0.75)" }}>
              Browse menus, manage your cart, and place demo orders.
            </Text>
          </div>

          {currentUser ? (
            <Space wrap>
              <Text style={{ color: "white" }}>
                Signed in as {currentUser.first_name || currentUser.email}
              </Text>
              <OrderHistory />
              <MyCart cartVersion={cartVersion} onCartChanged={handleCartChanged} />
              <Button onClick={handleLogout}>Logout</Button>
            </Space>
          ) : (
            <SignupForm />
          )}
        </div>
      </Header>

      <Content
        style={{
          padding: 32,
        }}
      >
        {loadingSession ? (
          <div style={{ display: "flex", justifyContent: "center", paddingTop: 120 }}>
            <Spin size="large" />
          </div>
        ) : currentUser ? (
          <FoodList onItemAdded={handleItemAdded} />
        ) : (
          <LoginForm onSuccess={refreshSession} />
        )}
      </Content>
    </Layout>
  );
}

export default App;
